import java.io.IOException;

@WebServlet("/sample011")
public class Sample011 extends HttpServlet {

    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String op = request.getParameter("op");
        if (op == null || op.isEmpty()) {
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Missing operation parameter");
            return;
        }
        UserDao2 userDao = new UserDao2();

        if ("selectAll".equals(op)) {
            response.setContentType("application/json;charset=UTF-8");
            response.setCharacterEncoding("UTF-8");
            try {
                response.getWriter().write(userDao.selectAll());
            } catch (Exception e) {
                response.sendError(HttpServletResponse.SC_INTERNAL_SERVER_ERROR, "Database error");
            }

        } else if ("add".equals(op)) {
            String name = request.getParameter("name");
            String pass = request.getParameter("pass");
            String xingming = request.getParameter("xingming");
            String zhuanye = request.getParameter("zhuanye");
            String banji = request.getParameter("banji");
            String xingbie = request.getParameter("xingbie");
            String tel = request.getParameter("tel");
            // Validate required fields
            if (name == null || pass == null || xingming == null) {
                response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Missing required fields");
                return;
            }
            UserBean userBean = new UserBean();
            userBean.setName(sanitize(name));
            userBean.setPass(sanitize(pass));
            userBean.setXingbie(sanitize(xingbie));
            userBean.setXingming(sanitize(xingming));
            userBean.setBanji(sanitize(banji));
            userBean.setZhuanye(sanitize(zhuanye));
            userBean.setTel(sanitize(tel));
            try {
                userDao.save(userBean);
            } catch (Exception e) {
                response.sendError(HttpServletResponse.SC_INTERNAL_SERVER_ERROR, "Save failed");
            }

        } else if ("selectUser".equals(op)) {
            String xingming = request.getParameter("xingming");
            if (xingming == null || xingming.isEmpty()) {
                response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Missing name parameter");
                return;
            }
            response.setContentType("application/json;charset=UTF-8");
            response.setCharacterEncoding("UTF-8");
            try {
                response.getWriter().write(userDao.selectUser(sanitize(xingming)));
            } catch (Exception e) {
                response.sendError(HttpServletResponse.SC_INTERNAL_SERVER_ERROR, "Query failed");
            }
        } else {
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid operation");
        }
    }

    private String sanitize(String input) {
        if (input == null) return null;
        // Basic sanitization: remove dangerous characters
        return input.replaceAll("[<>\"'%;()&+]", "");
    }

    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        doPost(request, response);
    }
